const input = $input.item.json;
const body = input.body || {};
const query = body.query || input.query || '';
const requestedPages = Number(body.maxPages || input.maxPages || 3);
const maxPages = Math.max(1, Math.min(Number.isFinite(requestedPages) ? requestedPages : 3, 5));

return Array.from({ length: maxPages }, (_, index) => ({
  json: {
    query,
    page: index + 1,
    source: 'boadica',
  },
}));

const payloads = $input.all().map((item) => item.json);

function firstString(...values) {
  for (const value of values) {
    if (typeof value === 'string' && value.trim()) return value.trim();
  }
  return null;
}

function formatCurrency(value) {
  if (!Number.isFinite(value)) return null;
  return `R$ ${value.toFixed(2).replace('.', ',')}`;
}

function imageUrl(product) {
  if (!product || !product.urlImagem) return null;
  if (product.urlImagem.startsWith('http://') || product.urlImagem.startsWith('https://')) {
    return product.urlImagem;
  }
  const imagePath = String(product.urlImagem);
  return `https://boadicastatic.blob.core.windows.net/images/prod/imagesprod/${imagePath.startsWith('/') ? imagePath.slice(1) : imagePath}`;
}

function normalizeItem(item) {
  const product = item.produto || {};
  const title = firstString(
    product.especificacao,
    [product.nomeFabricante, product.modelo].filter(Boolean).join(' '),
    product.nomeFabricante,
    product.modelo
  );
  if (!title) return null;

  const bestPrice = Number(item.precoMinimo || item.precoMaximo || 0);
  const link = `https://www.boadica.com.br/produtos/p${product.codProduto}`;

  return {
    title,
    product_page_url: link,
    link,
    image: imageUrl(product),
    sku: String(product.codProduto),
    brand: firstString(product.nomeFabricante, product.fabricante?.nome),
    source: 'boadica',
    source_name: 'Boa Dica',
    price_cash: Number.isFinite(bestPrice) && bestPrice > 0 ? bestPrice : null,
    price_cash_formatted: Number.isFinite(bestPrice) && bestPrice > 0 ? formatCurrency(bestPrice) : null,
    price_min: Number.isFinite(Number(item.precoMinimo)) ? Number(item.precoMinimo) : null,
    price_max: Number.isFinite(Number(item.precoMaximo)) ? Number(item.precoMaximo) : null,
    offers_count: Number.isFinite(Number(item.numLojas)) ? Number(item.numLojas) : null,
    description: firstString(product.especificacao, product.deschtml, product.desctxt),
  };
}

const productsBySku = new Map();
let totalProductsFound = 0;
let totalPages = 1;
let searchTerm = 'Não identificado';

for (const payload of payloads) {
  const results = Array.isArray(payload.resultados) ? payload.resultados : [];
  totalProductsFound = Math.max(totalProductsFound, Number(payload.totalEncontrado || 0));
  totalPages = Math.max(totalPages, Number(payload.paginas || 1));
  searchTerm = payload.termo || searchTerm;

  for (const item of results) {
    const product = normalizeItem(item);
    if (!product) continue;
    productsBySku.set(product.sku, product);
  }
}

const products = Array.from(productsBySku.values()).sort((a, b) => {
  const priceA = Number.isFinite(a.price_cash) ? a.price_cash : Number.POSITIVE_INFINITY;
  const priceB = Number.isFinite(b.price_cash) ? b.price_cash : Number.POSITIVE_INFINITY;
  return priceA - priceB;
});

return [{
  json: {
    products,
    total_products_found: totalProductsFound || products.length,
    total_products_returned: products.length,
    total_pages_available: totalPages,
    pages_fetched: payloads.length,
    search_term: searchTerm,
    source: 'boadica',
    source_name: 'Boa Dica',
    extracted_at: new Date().toISOString(),
  },
}];
